import React from "react";
import styled from "styled-components";
import { Link } from "react-router-dom";
import { FaArrowRight } from "react-icons/fa";

/**
 * Hero component with Meta-inspired design
 * @returns {JSX.Element} Hero component
 */
const Hero = () => {
  return (
    <HeroContainer>
      <HeroOverlay>
        <HeroContent>
          <HeroTextContent>
            <HeroTitle>Creating sustainable change in Tanzania</HeroTitle>
            <HeroDescription>
              We work with local communities to develop solutions that address the root causes of 
              poverty and create lasting positive change.
            </HeroDescription>
            <HeroButtons>
              <PrimaryButton to="/donate">Donate Now</PrimaryButton>
              <SecondaryButton to="/our-work">
                Learn More
                <ButtonIcon>
                  <FaArrowRight />
                </ButtonIcon>
              </SecondaryButton>
            </HeroButtons>
          </HeroTextContent>
        </HeroContent>
      </HeroOverlay>
    </HeroContainer>
  );
};

// Styled components with 2 spaces indentation
const HeroContainer = styled.section`
  background-color: var(--background-white);
  padding: 60px 0;
  overflow: hidden;

  @media (max-width: 768px) {
    padding: 40px 0;
  }
`;

const HeroContent = styled.div`
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
  display: flex;
  align-items: center;
  gap: 40px;

  @media (max-width: 1024px) {
    flex-direction: column;
    text-align: center;
  }
`;

const HeroTextContent = styled.div`
  flex: 1;
  max-width: 600px;

  @media (max-width: 1024px) {
    max-width: 100%;
    margin-bottom: 40px;
  }
`;

const HeroTitle = styled.h1`
  font-size: 42px;
  font-weight: 700;
  line-height: 1.1;
  margin-bottom: 20px;
  color: var(--text-primary);

  @media (max-width: 768px) {
    font-size: 32px;
  }
`;

const HeroDescription = styled.p`
  font-size: 18px;
  line-height: 1.5;
  margin-bottom: 32px;
  color: var(--text-secondary);
`;

const HeroButtons = styled.div`
  display: flex;
  gap: 16px;

  @media (max-width: 1024px) {
    justify-content: center;
  }

  @media (max-width: 480px) {
    flex-direction: column;
  }
`;

const Button = styled(Link)`
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 12px 24px;
  font-size: 16px;
  font-weight: 600;
  border-radius: 100px;
  text-decoration: none;
  transition: transform 0.2s ease, box-shadow 0.2s ease;

  &:hover {
    transform: translateY(-2px);
  }

  &:active {
    transform: translateY(0);
  }
`;

const PrimaryButton = styled(Button)`
  background-color: var(--primary-color);
  color: white;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);

  &:hover {
    background-color: var(--secondary-color);
    box-shadow: 0 6px 12px rgba(0, 0, 0, 0.15);
    color: white;
    transform: translateY(-2px);
    transition: all 0.3s ease;
  }
`;

const SecondaryButton = styled(Button)`
  background-color: var(--background-light);
  color: var(--primary-color);

  &:hover {
    background-color: var(--background-light);
    box-shadow: 0 6px 12px rgba(0, 0, 0, 0.1);
  }
`;

const ButtonIcon = styled.span`
  margin-left: 8px;
  display: inline-flex;
  font-size: 14px;
  transition: transform 0.2s ease;

  ${SecondaryButton}:hover & {
    transform: translateX(4px);
  }
`;

const HeroImageContainer = styled.div`
  flex: 1;
  max-width: 550px;

  @media (max-width: 1024px) {
    max-width: 100%;
    width: 100%;
  }
`;

const HeroImage = styled.img`
  width: 100%;
  height: auto;
  border-radius: 16px;
  box-shadow: 0 20px 40px rgba(0, 0, 0, 0.1);
  transition: transform 0.3s ease, box-shadow 0.3s ease;

  &:hover {
    transform: scale(1.02);
    box-shadow: 0 24px 48px rgba(0, 0, 0, 0.15);
  }
`;

export default Hero;
